fn verify_rsa_sha256(public_key: &[u8], signed_data: &[u8], sig: &[u8]) -> bool {
    use ring::signature::{RsaPublicKeyComponents, RSA_PKCS1_2048_8192_SHA256};

    // Parse RFC 3110 RSA public key format
    // First byte: exponent length (0 means 2-byte length follows)
    let (exp_len, exp_start) = if public_key.is_empty() {
        return false;
    } else if public_key[0] == 0 {
        if public_key.len() < 3 {
            return false;
        }
        let len = u16::from_be_bytes([public_key[1], public_key[2]]) as usize;
        (len, 3)
    } else {
        (public_key[0] as usize, 1)
    };

    if public_key.len() < exp_start + exp_len {
        return false;
    }

    let exponent = &public_key[exp_start..exp_start + exp_len];
    let modulus = &public_key[exp_start + exp_len..];

    if modulus.is_empty() {
        return false;
    }

    let components = RsaPublicKeyComponents { n: modulus, e: exponent };
    components.verify(&RSA_PKCS1_2048_8192_SHA256, signed_data, sig).is_ok()
