pub fn purge_expired(&mut self) {
    let before = self.entries.len();

    // Remove entries where all records are expired, moving them to stale store.
    // We must collect keys first because we mutate entries during iteration.
    let all_expired: Vec<(Vec<u8>, u16, u16)> = self
        .entries
        .iter()
        .filter(|(_, entries)| entries.iter().all(|e| e.is_expired()))
        .map(|(k, _)| k.clone())
        .collect();

    for key in &all_expired {
        // Move expired entries to stale store before removing
        if let Some(entries) = self.entries.pop(key) {
            self.stale_entries
                .entry(key.clone())
                .or_default()
                .extend(entries);
        }
    }

    // For entries with a mix of fresh and expired records, remove only the
    // expired sub-entries.  Collect the keys first; we pop & re-insert the
    // fresh subset.
    let mixed_keys: Vec<(Vec<u8>, u16, u16)> = self
        .entries
        .iter()
        .filter(|(_, entries)| {
            entries.iter().any(|e| e.is_expired()) && entries.iter().any(|e| !e.is_expired())
        })
        .map(|(k, _)| k.clone())
        .collect();

    for key in &mixed_keys {
        if let Some(entries) = self.entries.pop(key) {
            let mut fresh = Vec::new();
            let mut stale = Vec::new();
            for e in entries {
                if e.is_expired() {
                    stale.push(e);
                } else {
                    fresh.push(e);
                }
            }
            if !fresh.is_empty() {
                self.entries.put(key.clone(), fresh);
            }
            if !stale.is_empty() {
                self.stale_entries.entry(key.clone()).or_default().extend(stale);
            }
        }
    }

    // Purge stale entries that are too old
    let now = Instant::now();
    self.stale_entries.retain(|_, entries| {
        entries.retain(|e| now.duration_since(e.expires_at) < STALE_MAX_AGE);
        !entries.is_empty()
    });

    let after = self.entries.len();
    if before != after {
        debug!("purged {} expired cache entries", before - after);
    }
}

